processing.text:

if @@admin <> 1 and @type = 1 begin
  if @@sysDatabaseName.dbo.FastBusiness$System$GetAuthorize(@@admin, @@userID, 'SalesPrice', 'Edit') = 0 select @type = '0'
end

declare @message nvarchar(4000), @q nvarchar(4000), @duplicate nvarchar(4000), @field varchar(32), @r int
select @duplicate = case @@language when 'v' then N'Giá trị tại ô <span class="Highlight">%invalidCell</span> đã có hoặc lồng nhau.' else 'The value of cell <span class="Highlight">%invalidCell</span> is invalid or already exists.' end

create index i on @@table (ma_vt, ngay_ban, ma_nt)

if @type = '0' delete @@table from @@table a join dmgia2 b on a.loai_gia = b.loai_gia and a.ma_vt = b.ma_vt and a.ngay_ban = b.ngay_ban and a.ma_nt = b.ma_nt and a.ma_kho = b.ma_kho and a.ma_kh = b.ma_kh and a.nh_kh1 = b.nh_kh1 and a.nh_kh2 = b.nh_kh2 and a.nh_kh3 = b.nh_kh3 &Import.Operation.And;&Import.SalesPriceDirFields;

-- Checking
&Checking;
--
select dvt, he_so into #dmqddvt from dmqddvt where ma_vt = '*'
update @@table set dvt = b.dvt, he_so = 1 from @@table a join dmvt b on a.ma_vt = b.ma_vt where b.nhieu_dvt = 0
select @field = 'dvt', @r = min(stt)
  from @@table a join dmvt b on a.ma_vt = b.ma_vt and b.nhieu_dvt = 1
  where a.dvt not in (select dvt from #dmqddvt) and not exists(select 1 from dmqddvt c where c.ma_vt = a.ma_vt and c.dvt = a.dvt)
&Error;
update @@table set he_so = isnull(c.he_so, 1) from @@table a join dmvt b on a.ma_vt = b.ma_vt and b.nhieu_dvt = 1 join #dmqddvt c on a.dvt = c.dvt
update @@table set he_so = isnull(c.he_so, 1) from @@table a join dmvt b on a.ma_vt = b.ma_vt and b.nhieu_dvt = 1 join dmqddvt c on a.ma_vt = c.ma_vt and a.dvt = c.dvt
update @@table set gia_qd_nt2 = case when he_so = 0 then 0 else round(gia_nt2 / he_so, 9) end

select @field = 'ma_kho', @r = min(stt) from @@table where (ma_kho = '' and loai_gia in (select loai_gia from dmloaigia2 where charindex('S', xtype) > 0)) or (ma_kho <> '' and loai_gia not in (select loai_gia from dmloaigia2 where charindex('S', xtype) > 0))&Error;
select @field = 'ma_kh', @r = min(stt) from @@table where (ma_kh = '' and loai_gia in (select loai_gia from dmloaigia2 where charindex('C', xtype) > 0)) or (ma_kh <> '' and loai_gia not in (select loai_gia from dmloaigia2 where charindex('C', xtype) > 0))&Error;
select @field = 'nh_kh1', @r = min(stt) from @@table where (nh_kh1 = '' and loai_gia in (select loai_gia from dmloaigia2 where charindex('D', xtype) > 0)) or (nh_kh1 <> '' and loai_gia not in (select loai_gia from dmloaigia2 where charindex('D', xtype) > 0))&Error;
select @field = 'nh_kh2', @r = min(stt) from @@table where (nh_kh2 = '' and loai_gia in (select loai_gia from dmloaigia2 where charindex('E', xtype) > 0)) or (nh_kh2 <> '' and loai_gia not in (select loai_gia from dmloaigia2 where charindex('E', xtype) > 0))&Error;
select @field = 'nh_kh3', @r = min(stt) from @@table where (nh_kh3 = '' and loai_gia in (select loai_gia from dmloaigia2 where charindex('F', xtype) > 0)) or (nh_kh3 <> '' and loai_gia not in (select loai_gia from dmloaigia2 where charindex('F', xtype) > 0))&Error;
&Import.SalesPriceCheckFields;&Import.SalesPriceError;

select a.* into #k from @@table a join dmgia2 b on a.loai_gia = b.loai_gia and a.ma_vt = b.ma_vt and a.ngay_ban = b.ngay_ban and a.ma_nt = b.ma_nt and a.ma_kho = b.ma_kho and a.ma_kh = b.ma_kh and a.nh_kh1 = b.nh_kh1 and a.nh_kh2 = b.nh_kh2 and a.nh_kh3 = b.nh_kh3 &Import.Operation.And;&Import.SalesPriceDirFields;
delete @@table from @@table a join #k b on a.loai_gia = b.loai_gia and a.ma_vt = b.ma_vt and a.ngay_ban = b.ngay_ban and a.ma_nt = b.ma_nt and a.ma_kho = b.ma_kho and a.ma_kh = b.ma_kh and a.nh_kh1 = b.nh_kh1 and a.nh_kh2 = b.nh_kh2 and a.nh_kh3 = b.nh_kh3 &Import.Operation.And;&Import.SalesPriceDirFields;

-- Insert
&Inserting;

-- Update
if @type = '1' begin
  update dmgia2 set @@list from dmgia2 a join #k b on a.loai_gia = b.loai_gia and a.ma_vt = b.ma_vt and a.ngay_ban = b.ngay_ban and a.ma_nt = b.ma_nt and a.ma_kho = b.ma_kho and a.ma_kh = b.ma_kh and a.nh_kh1 = b.nh_kh1 and a.nh_kh2 = b.nh_kh2 and a.nh_kh3 = b.nh_kh3 &Import.Operation.And;&Import.SalesPriceDirFields;
end
